// Format actionable signals into an HTML email
const data = $input.first().json;
const actionable = data.actionable;
const allSignals = data.signals;
const totalScanned = data.total_scanned;
const now = new Date().toLocaleString('en-IN', {timeZone: 'Asia/Kolkata'});

let subject = `🎯 Trade Today Alert: ${actionable.length} Actionable Signal(s) Detected`;

let html = `
<div style="font-family: 'Segoe UI', Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%); color: white; padding: 24px; border-radius: 12px 12px 0 0;">
    <h1 style="margin: 0; font-size: 22px;">📈 Trade Today — Daily Watchlist Scan</h1>
    <p style="margin: 8px 0 0; opacity: 0.8; font-size: 14px;">🔍 Scanned ${totalScanned} stocks | 🎯 ${actionable.length} actionable signal(s)</p>
  </div>

  <div style="background: #fff3cd; border-left: 4px solid #ffc107; padding: 16px; margin: 0;">
    <h2 style="margin: 0 0 12px; font-size: 18px; color: #856404;">⚡ Actionable Signals</h2>
`;

for (const signal of actionable) {
  const bgColor = signal.recommendation === 'BUY' ? '#d4edda' : '#f8d7da';
  const borderColor = signal.recommendation === 'BUY' ? '#28a745' : '#dc3545';
  const emoji = signal.recommendation === 'BUY' ? '🟢' : '🔴';
  const riskColor = signal.risk_level.includes('HIGH') ? '#dc3545' :
                    signal.risk_level.includes('MEDIUM') ? '#ffc107' : '#28a745';

  html += `
    <div style="background: ${bgColor}; border-left: 4px solid ${borderColor}; padding: 12px 16px; margin: 8px 0; border-radius: 0 8px 8px 0;">
      <div style="font-size: 16px; font-weight: bold;">${emoji} ${signal.ticker}: <span style="color: ${borderColor};">${signal.recommendation}</span></div>
      <div style="font-size: 13px; color: #555; margin-top: 4px;">Risk: <span style="color: ${riskColor}; font-weight: bold;">${signal.risk_level}</span></div>
      <div style="font-size: 13px; color: #333; margin-top: 4px;">${signal.summary}</div>
    </div>
`;
}

html += `
  </div>

  <div style="padding: 16px; background: #f8f9fa; border-top: 1px solid #dee2e6;">
    <h2 style="margin: 0 0 12px; font-size: 18px; color: #333;">📋 Full Scan Report</h2>
    <table style="width: 100%; border-collapse: collapse; font-size: 14px;">
      <thead>
        <tr style="background: #e9ecef;">
          <th style="padding: 8px 12px; text-align: left; border-bottom: 2px solid #dee2e6;">Stock</th>
          <th style="padding: 8px 12px; text-align: center; border-bottom: 2px solid #dee2e6;">Signal</th>
          <th style="padding: 8px 12px; text-align: center; border-bottom: 2px solid #dee2e6;">Risk</th>
        </tr>
      </thead>
      <tbody>
`;

for (const signal of allSignals) {
  const signalColor = signal.recommendation === 'BUY' ? '#28a745' :
                      signal.recommendation === 'SELL' ? '#dc3545' : '#6c757d';
  const emoji = signal.recommendation === 'BUY' ? '🟢' :
                signal.recommendation === 'SELL' ? '🔴' : '🟡';

  html += `
        <tr style="border-bottom: 1px solid #dee2e6;">
          <td style="padding: 8px 12px; font-weight: bold;">${signal.ticker}</td>
          <td style="padding: 8px 12px; text-align: center; color: ${signalColor}; font-weight: bold;">${emoji} ${signal.recommendation}</td>
          <td style="padding: 8px 12px; text-align: center;">${signal.risk_level}</td>
        </tr>
`;
}

html += `
      </tbody>
    </table>
  </div>

  <div style="background: #1a1a2e; color: #aaa; padding: 16px; border-radius: 0 0 12px 12px; font-size: 12px; text-align: center;">
    ⏰ Generated at ${now} IST | Trade Today AI Trading Swarm
  </div>
</div>
`;

return [{
  json: {
    subject: subject,
    html_body: html,
    actionable_count: actionable.length,
    total_scanned: totalScanned
  }
}];

